mapper.select:
SELECT L.LECTURE_NO AS lectureNo, L.LECTURE_NAME AS lectureName, L.PROFESSOR_NAME AS professorName, NVL(AVG(A.TOTAL_SCORE), 0) AS avgScore, COUNT(A.ASSE_NO) AS reviewCount, ROUND(NVL(AVG(A.HOMEWORK), 0)) AS homework, ROUND(NVL(AVG(A.GRADE), 0)) AS grade FROM LECTURE L JOIN DEPARTMENT D ON (L.DEPT_NO = D.DEPT_NO) LEFT JOIN LECTURE_ASSESSMENT A ON L.LECTURE_NO = A.LECTURE_NO WHERE D.UNI_NO = #{uniNo}
AND ( L.LECTURE_NAME LIKE '%' || #{keyword} || '%' OR L.PROFESSOR_NAME LIKE '%' || #{keyword} || '%' )
GROUP BY L.LECTURE_NO, L.LECTURE_NAME, L.PROFESSOR_NAME ORDER BY L.LECTURE_NO DESC

SELECT L.LECTURE_NO as "lectureNo", L.LECTURE_NAME as "lectureName", L.PROFESSOR_NAME as "professorName", D.UNI_NO as "uniNo" FROM LECTURE L JOIN DEPARTMENT D ON (L.DEPT_NO = D.DEPT_NO) WHERE D.UNI_NO = #{uniNo}
AND (L.LECTURE_NAME LIKE '%' || #{keyword} || '%' OR L.PROFESSOR_NAME LIKE '%' || #{keyword} || '%')
ORDER BY L.LECTURE_NAME ASC
